sql:
SELECT nature
FROM trades
WHERE updated_at < DATE('now', '-6 months');

external_knowledge:
- Smaller deals refer to trades with a notional amount under 500 thousand; 
- Higher base prices indicate an underlying price greater than 2000; 
- Buyers of protection are those with a 'Protection buyer' position in the trade.

sql:
SELECT currencies.currency_code, trades.notional_amount
FROM trades
JOIN currencies ON trades.base_currency = currencies.currency_code;

SELECT trades.nature, positions.position_type, trades.notional_amount
FROM trades
INNER JOIN positions ON trades.position = positions.position_type;

SELECT nature, residual_maturity, market_value
FROM trades
WHERE reference_entity_id = 1;

SELECT * 
FROM trades 
WHERE pay_leg = 'Floating' AND option_position = 'Put';

SELECT trade_id, nature, residual_maturity, base_currency, notional_amount
FROM trades
WHERE notional_amount > (SELECT AVG(notional_amount) FROM trades);

SELECT trade_id, nature, residual_maturity, market_value
FROM trades
WHERE market_value = (SELECT MAX(market_value) FROM trades);

external_knowledge:
- 'base value' refers to 'underlying price';
- 'strike value' refers to 'strike price';
- 'trader' corresponds to 'user_name';
- 'identifier' refers to 'trade_id';
- 'first few' indicates a limit of 10.
